changeSet.sql:
-- Create temp table with duplicate tenant document IDs to delete CREATE TEMP TABLE temp_to_delete_tenant AS SELECT id FROM ( SELECT id, ROW_NUMBER() OVER ( PARTITION BY tenant_id, document_category ORDER BY CASE document_status WHEN 'DECLINED' THEN 3 WHEN 'TO_PROCESS' THEN 2 ELSE 1 END DESC, id DESC ) as rn FROM public.document WHERE tenant_id IS NOT NULL AND document_category IN ('TAX', 'RESIDENCY', 'IDENTIFICATION', 'PROFESSIONAL') ) t WHERE rn > 1;
-- Flag storage files of the soon-to-be-deleted tenant documents for deletion UPDATE public.storage_file SET status = 'TO_DELETE' WHERE id IN ( SELECT watermark_file_id FROM public.document WHERE id IN (SELECT id FROM temp_to_delete_tenant) AND watermark_file_id IS NOT NULL UNION SELECT storage_file_id FROM public.file WHERE document_id IN (SELECT id FROM temp_to_delete_tenant) AND storage_file_id IS NOT NULL UNION SELECT preview_file_id FROM public.file WHERE document_id IN (SELECT id FROM temp_to_delete_tenant) AND preview_file_id IS NOT NULL );
-- Delete duplicate tenant documents DELETE FROM public.document WHERE id IN (SELECT id FROM temp_to_delete_tenant);
DROP TABLE temp_to_delete_tenant;

-- Create temp table with duplicate guarantor document IDs to delete CREATE TEMP TABLE temp_to_delete_guarantor AS SELECT id FROM ( SELECT id, ROW_NUMBER() OVER ( PARTITION BY guarantor_id, document_category ORDER BY CASE document_status WHEN 'DECLINED' THEN 3 WHEN 'TO_PROCESS' THEN 2 ELSE 1 END DESC, id DESC ) as rn FROM public.document WHERE guarantor_id IS NOT NULL AND document_category IN ('TAX', 'RESIDENCY', 'IDENTIFICATION', 'PROFESSIONAL') ) t WHERE rn > 1;
-- Flag storage files of the soon-to-be-deleted guarantor documents for deletion UPDATE public.storage_file SET status = 'TO_DELETE' WHERE id IN ( SELECT watermark_file_id FROM public.document WHERE id IN (SELECT id FROM temp_to_delete_guarantor) AND watermark_file_id IS NOT NULL UNION SELECT storage_file_id FROM public.file WHERE document_id IN (SELECT id FROM temp_to_delete_guarantor) AND storage_file_id IS NOT NULL UNION SELECT preview_file_id FROM public.file WHERE document_id IN (SELECT id FROM temp_to_delete_guarantor) AND preview_file_id IS NOT NULL );
-- Delete duplicate guarantor documents DELETE FROM public.document WHERE id IN (SELECT id FROM temp_to_delete_guarantor);
DROP TABLE temp_to_delete_guarantor;
